<h1 class="h5">Crear cotización</h1><form method="POST" class="row g-2"><?= csrf_campo() ?><div class="col-md-3"><label class="small">Número</label><input class="form-control" value="<?= e($siguienteNumero) ?>" disabled></div><div class="col-md-3"><label class="small">Cliente</label><select class="form-select" name="cliente_id"><?php foreach($clientes as $c): ?><option value="<?= $c['id'] ?>"><?= e($c['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label class="small">Estado</label><select class="form-select" name="estado"><option>borrador</option><option>enviada</option><option>aprobada</option><option>rechazada</option></select></div><div class="col-md-3"><label class="small">Producto</label><select class="form-select" name="producto_id"><?php foreach($productos as $p): ?><option value="<?= $p['id'] ?>"><?= e($p['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label class="small">Cantidad</label><input class="form-control" name="cantidad" type="number" step="0.01" value="1"></div><div class="col-md-2"><label class="small">Precio</label><input class="form-control" name="precio_unitario" type="number" step="0.01" value="0"></div><div class="col-md-2"><label class="small">Impuesto %</label><input class="form-control" name="impuesto_item" type="number" step="0.01" value="19"></div><div class="col-md-6"><label class="small">Descripción ítem</label><input class="form-control" name="descripcion_item"></div><div class="col-md-3"><label class="small">Fecha emisión</label><input class="form-control" type="date" name="fecha_emision" value="<?= date('Y-m-d') ?>"></div><div class="col-md-3"><label class="small">Fecha vencimiento</label><input class="form-control" type="date" name="fecha_vencimiento" value="<?= date('Y-m-d', strtotime('+15 days')) ?>"></div><div class="col-md-6"><label class="small">Observaciones</label><input class="form-control" name="observaciones"></div><div class="col-md-6"><label class="small">Términos</label><input class="form-control" name="terminos_condiciones"></div><div class="col-12"><button class="btn btn-primary btn-sm">Guardar cotización</button></div></form>
